#include <vector>
#include <queue>
#include <unordered_map>
#include <climits>
#include <algorithm>

using namespace std;

long long solve(vector<vector<long long>> edges, vector<bool> online, long long k) {
    int n = online.size();
    unordered_map<int, vector<pair<int, long long>>> graph;
    for (const auto& edge : edges) {
        int u = edge[0];
        int v = edge[1];
        long long cost = edge[2];
        graph[u].emplace_back(v, cost);
    }

    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> pq;
    pq.emplace(LONG_MAX, 0);
    vector<vector<long long>> visited(n, vector<long long>(k + 1, -1));

    while (!pq.empty()) {
        long long current_min = pq.top().first;
        int node = pq.top().second;
        pq.pop();

        if (node == n - 1) {
            return current_min;
        }

        for (const auto& [neighbor, cost] : graph[node]) {
            if (!online[neighbor]) continue;
            long long new_total = current_min + cost;
            long long new_min = min(current_min, cost);

            if (new_total <= k && new_min > visited[neighbor][new_total]) {
                visited[neighbor][new_total] = new_min;
                pq.emplace(new_min, neighbor);
            }
        }
    }

    return -1;
}
